// Parse the OpenAI response
const response = $input.first().json;
let content = response.text || response.output || response.message?.content || '';

// If content is empty, try to get it from the response object directly
if (!content && typeof response === 'object') {
  content = JSON.stringify(response);
}

try {
  // Clean up any markdown formatting
  let cleanJson = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleanJson);

  return {
    json: {
      ...parsed,
      original_email: $('Gmail Trigger').first().json
    }
  };
} catch (e) {
  return {
    json: {
      is_quote_request: false,
      confidence: 0,
      detected_signals: [],
      reasoning: 'Failed to parse AI response: ' + e.message,
      original_email: $('Gmail Trigger').first().json
    }
  };
}

// Normalize data from both sources
const item = $input.first().json;

let normalized = {
  source: 'unknown',
  raw_content: '',
  contact_email: '',
  timestamp: new Date().toISOString()
};

// Check if from email path (has original_email from Parse Filter)
if (item.original_email) {
  normalized.source = 'email';
  normalized.raw_content = item.original_email.text || item.original_email.textPlain || item.original_email.snippet || '';

  // Extract email - original_email.from.value[0].address structure
  if (item.original_email.from && item.original_email.from.value && item.original_email.from.value[0]) {
    normalized.contact_email = item.original_email.from.value[0].address || '';
  }

  normalized.subject = item.original_email.subject || '';
  normalized.email_id = item.original_email.id || '';
}
// Check if from form path
else if (item.body || item.name) {
  normalized.source = 'form';
  normalized.raw_content = JSON.stringify(item.body || item);
  normalized.contact_email = item.email || item.body?.email || '';
  normalized.contact_name = item.name || item.body?.name || '';
  normalized.company_name = item.company || item.body?.company || '';
  normalized.phone = item.phone || item.body?.phone || '';
  normalized.service_type = item.service_type || item.body?.service_type || '';
  normalized.budget = item.budget || item.body?.budget || '';
  normalized.timeline = item.timeline || item.body?.timeline || '';
  normalized.message = item.message || item.body?.message || '';
}

return { json: normalized };

// Parse the extraction response
const response = $input.first().json;
let content = response.text || response.output || response.message?.content || '';
const normalized = $('Normalize Data').first().json;

try {
  let cleanJson = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const extracted = JSON.parse(cleanJson);

  return {
    json: {
      ...extracted,
      source: normalized.source,
      raw_content: normalized.raw_content,
      email_id: normalized.email_id || null,
      received_at: normalized.timestamp
    }
  };
} catch (e) {
  return {
    json: {
      contact_name: 'Unknown',
      company_name: 'Unknown',
      email: normalized.contact_email || 'user@example.com',
      phone: null,
      service_type: 'other',
      budget_range: null,
      timeline: 'Unknown',
      special_requirements: null,
      decision_maker: false,
      complexity_score: 5,
      urgency_level: 'medium',
      value_estimate: 10000,
      qualification_score: 30,
      source: normalized.source,
      raw_content: normalized.raw_content,
      parse_error: e.message
    }
  };
}

// Prepare data for Supabase insert
const extracted = $input.first().json;

return {
  json: {
    contact_name: extracted.contact_name || 'Unknown',
    company_name: extracted.company_name || 'Unknown',
    email: extracted.email,
    phone: extracted.phone,
    service_type: extracted.service_type,
    budget_range: extracted.budget_range,
    timeline: extracted.timeline,
    special_requirements: extracted.special_requirements,
    complexity_score: extracted.complexity_score,
    urgency_level: extracted.urgency_level,
    value_estimate: extracted.value_estimate,
    qualification_score: extracted.qualification_score,
    source: extracted.source,
    status: 'PROCESSING'
  }
};

// Parse pricing response
const response = $input.first().json;
let content = response.text || response.output || response.message?.content || '';

try {
  let cleanJson = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const pricing = JSON.parse(cleanJson);

  // Get record ID from Supabase save
  const supabaseResult = $('Supabase - Save Initial').first().json;
  const recordId = Array.isArray(supabaseResult) ? supabaseResult[0]?.id : supabaseResult?.id;

  return {
    json: {
      ...pricing,
      extracted: $('Parse Extraction').first().json,
      record_id: recordId
    }
  };
} catch (e) {
  const estimate = $('Parse Extraction').first().json.value_estimate || 10000;
  const supabaseResult = $('Supabase - Save Initial').first().json;
  const recordId = Array.isArray(supabaseResult) ? supabaseResult[0]?.id : supabaseResult?.id;

  return {
    json: {
      good_price: Math.round(estimate * 0.8),
      better_price: Math.round(estimate),
      best_price: Math.round(estimate * 1.4),
      recommended_tier: 'better',
      pricing_rationale: 'Fallback pricing based on estimate',
      extracted: $('Parse Extraction').first().json,
      record_id: recordId
    }
  };
}

